#!/usr/bin/env node
// ---------------------------------------------------------------------------
// PreToolUse guard: block edits to auto-generated Supabase files
// ---------------------------------------------------------------------------
// client.ts and types.ts carry a "automatically generated, do not edit"
// banner and are regenerated from the live schema. Hand-edits get silently
// overwritten on the next regen, so we deny the edit and point you at the
// right tool (Supabase CLI / Management API).
//
// Registered in .claude/settings.json under PreToolUse (Edit|MultiEdit|Write).
// Fail-open: any parsing/logic error allows the edit (exit 0, no decision).
// ---------------------------------------------------------------------------

import { readFileSync } from "node:fs";

const BACKSLASH = String.fromCharCode(92); // avoids fragile escaping

// Repo-relative (forward-slash) paths that must not be hand-edited.
const PROTECTED = [
  "src/integrations/supabase/client.ts",
  "src/integrations/supabase/types.ts",
];

function allow() {
  process.exit(0);
}

function deny(reason) {
  process.stdout.write(
    JSON.stringify({
      hookSpecificOutput: {
        hookEventName: "PreToolUse",
        permissionDecision: "deny",
        permissionDecisionReason: reason,
      },
    })
  );
  process.exit(0);
}

try {
  let raw = "";
  try {
    raw = readFileSync(0, "utf8");
  } catch {
    raw = "";
  }

  const input = JSON.parse(raw || "{}");
  const filePath =
    (input && input.tool_input && (input.tool_input.file_path || input.tool_input.path)) || "";

  if (!filePath) allow();

  const normalized = String(filePath).split(BACKSLASH).join("/");
  const hit = PROTECTED.find((p) => normalized.endsWith(p));

  if (hit) {
    deny(
      `"${hit}" is auto-generated by Supabase (do-not-edit banner). ` +
        `Regenerate it with the Supabase CLI / Management API instead of editing by hand.`
    );
  }

  allow();
} catch {
  allow();
}
